+// Modify drawCharacter to use idle animation frames with 200ms interval and looping
+import { performance } from 'perf_hooks'; // if needed for time, else use Date.now()
+
+function drawCharacter(character: Character, ctx: CanvasRenderingContext2D, x: number, y: number) {
+  const frames = IDLE_FRAMES_MAP[character.type];
+  if (!frames) {
+    // fallback to single sprite draw
+    drawSprite(character.sprite, ctx, x, y);
+    return;
+  }
+  // Calculate frame index based on time and frame duration
+  const now = Date.now();
+  const frameIndex = Math.floor(now / IDLE_FRAME_DURATION) % frames.length;
+  const frame = frames[frameIndex];
+
+  // For breathing vertical offset: offset y by -1 on frame 1 (breathing up)
+  let yOffset = 0;
+  if (frameIndex === 1) {
+    yOffset = -1;
+  }
+
+  drawSprite(frame, ctx, x, y + yOffset);
